import React, { useEffect, useState } from 'react';
import { paymentMethods, transactionCategories } from '../constants';
import { getMonthValue } from '../utils';

const initialState = {
  title: '',
  amount: '',
  type: 'expense',
  category: 'food',
  paymentMethod: 'bank_transfer',
  notes: '',
  date: `${getMonthValue()}-01`,
};

const TransactionForm = ({ editingTransaction, onSubmit, onCancel, saving }) => {
  const [form, setForm] = useState(initialState);

  useEffect(() => {
    if (editingTransaction) {
      setForm({
        title: editingTransaction.title,
        amount: editingTransaction.amount,
        type: editingTransaction.type,
        category: editingTransaction.category,
        paymentMethod: editingTransaction.paymentMethod,
        notes: editingTransaction.notes || '',
        date: editingTransaction.date.slice(0, 10),
      });
    } else {
      setForm(initialState);
    }
  }, [editingTransaction]);

  const handleChange = (event) => {
    const { name, value } = event.target;
    setForm((current) => ({ ...current, [name]: value }));
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    onSubmit({
      ...form,
      amount: Number(form.amount),
    });
  };

  return (
    <div className="panel">
      <h3 className="panel-title">{editingTransaction ? 'Edit Transaction' : 'Add Transaction'}</h3>
      <p className="panel-subtitle">Track every inflow and outflow with category-level detail.</p>

      <form className="form-grid" onSubmit={handleSubmit}>
        <div className="field">
          <label htmlFor="title">Title</label>
          <input id="title" name="title" value={form.title} onChange={handleChange} placeholder="Salary payment" required />
        </div>

        <div className="field">
          <label htmlFor="amount">Amount</label>
          <input id="amount" name="amount" type="number" min="0.01" step="0.01" value={form.amount} onChange={handleChange} required />
        </div>

        <div className="field">
          <label htmlFor="type">Type</label>
          <select id="type" name="type" value={form.type} onChange={handleChange}>
            <option value="income">Income</option>
            <option value="expense">Expense</option>
          </select>
        </div>

        <div className="field">
          <label htmlFor="category">Category</label>
          <select id="category" name="category" value={form.category} onChange={handleChange}>
            {transactionCategories.map((category) => (
              <option key={category} value={category}>
                {category}
              </option>
            ))}
          </select>
        </div>

        <div className="field">
          <label htmlFor="paymentMethod">Payment Method</label>
          <select id="paymentMethod" name="paymentMethod" value={form.paymentMethod} onChange={handleChange}>
            {paymentMethods.map((method) => (
              <option key={method} value={method}>
                {method}
              </option>
            ))}
          </select>
        </div>

        <div className="field">
          <label htmlFor="date">Date</label>
          <input id="date" name="date" type="date" value={form.date} onChange={handleChange} required />
        </div>

        <div className="field">
          <label htmlFor="notes">Notes</label>
          <textarea id="notes" name="notes" value={form.notes} onChange={handleChange} placeholder="Optional memo" />
        </div>

        <div style={{ display: 'flex', gap: 10 }}>
          <button type="submit" className="button" disabled={saving}>
            {saving ? 'Saving...' : editingTransaction ? 'Update transaction' : 'Create transaction'}
          </button>
          {editingTransaction ? (
            <button type="button" className="button-ghost" onClick={onCancel}>
              Cancel
            </button>
          ) : null}
        </div>
      </form>
    </div>
  );
};

export default TransactionForm;
